import React, { useEffect, useState } from 'react';
import api from '../../services/api';
import { FileText, Image as ImageIcon, ShoppingBag } from 'lucide-react';

const Dashboard = () => {
  const [stats, setStats] = useState({ posts: 0, media: 0, products: 0 });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const [postsRes, mediaRes, productsRes] = await Promise.all([
          api.get('/posts?limit=1'),
          api.get('/media?limit=1'),
          api.get('/products')
        ]);
        setStats({
          posts: postsRes.data.total || 0,
          media: mediaRes.data.total || 0,
          products: productsRes.data?.length || 0
        });
      } catch (error) {
        console.error('Error fetching stats:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  if (loading) return <div>Loading dashboard...</div>;

  return (
    <div>
      <h1 className="text-3xl font-serif font-bold mb-8">Dashboard Overview</h1>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {/* Posts Stat Card */}
        <div className="bg-white p-6 rounded-lg border border-border shadow-sm flex items-center gap-4">
          <div className="p-4 bg-gray-light rounded-full">
            <FileText size={24} className="text-black" />
          </div>
          <div>
            <p className="text-sm text-gray-dark font-medium uppercase tracking-wider">Total Posts</p>
            <p className="text-3xl font-bold">{stats.posts}</p>
          </div>
        </div>

        {/* Media Stat Card */}
        <div className="bg-white p-6 rounded-lg border border-border shadow-sm flex items-center gap-4">
          <div className="p-4 bg-gray-light rounded-full">
            <ImageIcon size={24} className="text-black" />
          </div>
          <div>
            <p className="text-sm text-gray-dark font-medium uppercase tracking-wider">Media Files</p>
            <p className="text-3xl font-bold">{stats.media}</p>
          </div>
        </div>

        {/* Products Stat Card */}
        <div className="bg-white p-6 rounded-lg border border-border shadow-sm flex items-center gap-4">
          <div className="p-4 bg-gray-light rounded-full">
            <ShoppingBag size={24} className="text-black" />
          </div>
          <div>
            <p className="text-sm text-gray-dark font-medium uppercase tracking-wider">Products</p>
            <p className="text-3xl font-bold">{stats.products}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
